const body = $input.first().json;
const msg = body.message || (body.callback_query ? body.callback_query.message : null);
const cb = body.callback_query;
const from = cb ? cb.from : body.message.from;
const out = {
  telegramId: from.id, username: from.username || '', firstName: from.first_name || '',
  chatId: msg.chat.id, messageId: msg.message_id, isCallback: !!cb,
  callbackData: cb ? cb.data : null, callbackQueryId: cb ? cb.id : null,
  text: (body.message && body.message.text) ? body.message.text : '',
  hasPhoto: !!(body.message && body.message.photo),
  photoFileId: (body.message && body.message.photo) ? body.message.photo[body.message.photo.length - 1].file_id : null,
};
if (out.isCallback) out.routeType = 'callback';
else if (out.text.indexOf('/start') === 0) out.routeType = 'start';
else if (out.text.indexOf('/myaccount') === 0) out.routeType = 'myaccount';
else if (out.text.indexOf('/admin') === 0) out.routeType = 'admin';
else if (out.hasPhoto) out.routeType = 'photo_receipt';
else out.routeType = 'other_text';
const refMatch = out.text.match(/\/start(?:@\w+)?\s+ref_(\d+)/);
out.referrerId = refMatch ? refMatch[1] : null;
return [{ json: out }];

const lang = $json.language || ($('Parse Update').item.json.callbackData === 'lang_fa' ? 'fa' : 'en');
const fa = {
  text: '🏠 منوی اصلی NovaTunnel\nاز دکمه‌های زیر استفاده کن:',
  buttons: [
    [{ text: '🛒 خرید اشتراک VPN', callback_data: 'buy_plan' }],
    [{ text: '📦 اشتراک‌های فعال من', callback_data: 'my_subs' }, { text: '🔑 حساب من', callback_data: 'my_account' }],
    [{ text: '💳 کیف پول من', callback_data: 'wallet' }, { text: '📣 دعوت از دوستان', callback_data: 'referral' }],
    [{ text: '📞 پشتیبانی', callback_data: 'support' }, { text: 'ℹ️ درباره ما', callback_data: 'about' }],
  ]
};
const en = {
  text: '🏠 NovaTunnel Main Menu\nChoose an option below:',
  buttons: [
    [{ text: '🛒 Buy VPN Plan', callback_data: 'buy_plan' }],
    [{ text: '📦 My Subscriptions', callback_data: 'my_subs' }, { text: '🔑 My Account', callback_data: 'my_account' }],
    [{ text: '💳 My Wallet', callback_data: 'wallet' }, { text: '📣 Refer a Friend', callback_data: 'referral' }],
    [{ text: '📞 Support', callback_data: 'support' }, { text: 'ℹ️ About Us', callback_data: 'about' }],
  ]
};
const t = lang === 'fa' ? fa : en;
return [{ json: { chatId: $('Parse Update').item.json.chatId, text: t.text, buttons: t.buttons, lang } }];

const plans = {
  plan_1m:  { months: 1,  gb: 30,  price: 150000, label_fa: '۱ ماهه', label_en: '1 Month' },
  plan_3m:  { months: 3,  gb: 100, price: 390000, label_fa: '۳ ماهه', label_en: '3 Months' },
  plan_6m:  { months: 6,  gb: 200, price: 690000, label_fa: '۶ ماهه', label_en: '6 Months' },
  plan_12m: { months: 12, gb: 500, price: 1190000, label_fa: '۱ ساله', label_en: '1 Year' },
};
const data = $('Parse Update').item.json;
const plan = plans[data.callbackData];
return [{ json: { ...data, plan, planKey: data.callbackData } }];

const cb = $('Parse Update').item.json.callbackData || '';
let action = null, telegramId = $('Parse Update').item.json.telegramId, planKey = null, targetUser = null;
let m;
if ((m = cb.match(/^pay_zarinpal_(.+)$/))) { action = 'pay_zarinpal'; planKey = m[1]; }
else if ((m = cb.match(/^pay_card_(.+)$/))) { action = 'pay_card'; planKey = m[1]; }
else if ((m = cb.match(/^pay_crypto_(.+)$/))) { action = 'pay_crypto'; planKey = m[1]; }
else if ((m = cb.match(/^approve_(\d+)_(.+)$/))) { action = 'approve'; targetUser = m[1]; planKey = m[2]; }
else if ((m = cb.match(/^reject_(\d+)$/))) { action = 'reject'; targetUser = m[1]; }
return [{ json: { action, telegramId, planKey, targetUser, chatId: $('Parse Update').item.json.chatId } }];

const crypto = require('crypto');
const body = $input.first().json;
const sorted = JSON.stringify(body, Object.keys(body).sort());
const expected = crypto.createHmac('sha512', $env.NOWPAYMENTS_IPN_SECRET).update(sorted).digest('hex');
const received = $('Nowpayments IPN Webhook').item.json.headers['x-nowpayments-sig'];
return [{ json: { ...body, signatureValid: expected === received } }];

const plans = {
  plan_1m:  { months: 1,  gb: 30,  price: 150000, label_fa: '۱ ماهه', label_en: '1 Month' },
  plan_3m:  { months: 3,  gb: 100, price: 390000, label_fa: '۳ ماهه', label_en: '3 Months' },
  plan_6m:  { months: 6,  gb: 200, price: 690000, label_fa: '۶ ماهه', label_en: '6 Months' },
  plan_12m: { months: 12, gb: 500, price: 1190000, label_fa: '۱ ساله', label_en: '1 Year' },
};
const d = $json;
return [{ json: { telegramId: d.telegramId, chatId: d.telegramId, planKey: d.planKey, plan: plans[d.planKey] } }];

const { randomUUID } = require('crypto');
const upstream = $('Lookup Plan By Key').item.json;
const plan = upstream.plan;
const clientUuid = randomUUID();
const email = 'nt_' + upstream.telegramId + '_' + Date.now();
const expiryMs = Date.now() + (plan.months * 30 * 24 * 60 * 60 * 1000);
return [{ json: { clientUuid, email, expiryMs, trafficGB: plan.gb, telegramId: upstream.telegramId, planKey: upstream.planKey, plan } }];

const d = $('Generate Client UUID+Email').item.json;
const host = $env.XUI_PANEL_DOMAIN || '94.75.223.106';
const port = $env.XUI_VLESS_PORT || '443';
const vlessLink = `vless://${d.clientUuid}@${host}:${port}?security=tls&type=tcp#NovaTunnel-${d.email}`;
return [{ json: { ...d, vlessLink } }];

