const items = $input.all().map(i => i.json);
const now = Date.now();
return items.map(s => {
  const remainMs = new Date(s.expiry_at).getTime() - now;
  const isToday = remainMs <= 24*60*60*1000;
  return { json: { ...s, isToday } };
});
